class Solution:
    def reverseKGroup(self, head, k):
        def get_kth(curr, k):
            while curr and k > 1:
                curr = curr.next
                k -= 1
            return curr

        dummy = ListNode(0, head)
        group_prev = dummy
        while True:
            kth = get_kth(group_prev, k + 1)
            if not kth:
                break
            group_next = kth.next
            prev, curr = kth.next, group_prev.next
            while curr != group_next:
                nxt = curr.next
                curr.next = prev
                prev = curr
                curr = nxt
            tmp = group_prev.next
            group_prev.next = kth
            group_prev = tmp
        return dummy.next

