            if v in visited:
                continue
            visited.add(v)
            total += cost
            x, y = points[v]
            for j in range(n):
                if j not in visited:
                    xj, yj = points[j]
                    heapq.heappush(heap, (abs(x - xj) + abs(y - yj), v, j))
        return total

